    const dstRatio = dstW / dstH;
    let sx = 0, sy = 0, sw = srcW, sh = srcH;
    if (srcRatio > dstRatio) {
      // source wider
      sh = srcH;
      sw = sh * dstRatio;
      sx = (srcW - sw) / 2;
    } else {
      // source taller
      sw = srcW;
      sh = sw / dstRatio;
      sy = (srcH - sh) / 2;
