import { useEffect, useRef, useState } from 'react';

interface Position {
  x: number;
  y: number;
}

interface Connection {
  from: Position;
  to: Position;
  type: 'parent' | 'child' | 'spouse';
  path?: string; // AI-generated SVG path
  fromMemberId?: string;
  toMemberId?: string;
}

interface FamilyConnectorLinesProps {
  containerRef: React.RefObject<HTMLDivElement>;
  connections: Connection[];
}

// Generate smooth curved path between two points
const generateCurvedPath = (from: Position, to: Position, type: 'parent' | 'child' | 'spouse'): string => {
  const dx = to.x - from.x;
  const dy = to.y - from.y;
  
  if (type === 'spouse') {
    // For spouse - simple straight line with slight curve
    const midY = from.y;
    return `M ${from.x} ${from.y} Q ${from.x + dx / 2} ${midY - 10} ${to.x} ${to.y}`;
  }
  
  if (type === 'parent') {
    // For parent - elegant bezier curve going UP from child to parent
    const controlY = from.y - Math.abs(dy) * 0.5;
    
    return `M ${from.x} ${from.y} C ${from.x} ${controlY}, ${to.x} ${to.y + Math.abs(dy) * 0.3}, ${to.x} ${to.y}`;
  }
  
  // For child - elegant bezier curve going DOWN from heart to child
  const controlY = from.y + Math.abs(dy) * 0.5;
  
  return `M ${from.x} ${from.y} C ${from.x} ${controlY}, ${to.x} ${to.y - Math.abs(dy) * 0.3}, ${to.x} ${to.y}`;
};

export const FamilyConnectorLines = ({ containerRef, connections }: FamilyConnectorLinesProps) => {
  const svgRef = useRef<SVGSVGElement>(null);
  const [dimensions, setDimensions] = useState({ width: 0, height: 0 });

  useEffect(() => {
    const updateDimensions = () => {
      if (containerRef.current) {
        setDimensions({
          width: containerRef.current.scrollWidth,
          height: containerRef.current.scrollHeight,
        });
      }
    };

    updateDimensions();
    window.addEventListener('resize', updateDimensions);
    
    // Use ResizeObserver for container size changes
    const resizeObserver = new ResizeObserver(updateDimensions);
    if (containerRef.current) {
      resizeObserver.observe(containerRef.current);
    }

    return () => {
      window.removeEventListener('resize', updateDimensions);
      resizeObserver.disconnect();
    };
  }, [containerRef, connections]);

  if (connections.length === 0) return null;

  return (
    <svg
      ref={svgRef}
      className="absolute inset-0 pointer-events-none z-0"
      width={dimensions.width}
      height={dimensions.height}
      style={{ overflow: 'visible' }}
    >
      <defs>
        {/* Gradient for parent lines - going up */}
        <linearGradient id="parentLineGradient" x1="0%" y1="100%" x2="0%" y2="0%">
          <stop offset="0%" stopColor="hsl(var(--muted-foreground))" stopOpacity="0.6" />
          <stop offset="100%" stopColor="#ef4444" stopOpacity="0.4" />
        </linearGradient>
        
        {/* Gradient for child lines - going down */}
        <linearGradient id="childLineGradient" x1="0%" y1="0%" x2="0%" y2="100%">
          <stop offset="0%" stopColor="#ef4444" stopOpacity="0.6" />
          <stop offset="100%" stopColor="hsl(var(--muted-foreground))" stopOpacity="0.4" />
        </linearGradient>
        
        {/* Filter for subtle glow effect */}
        <filter id="lineGlow" x="-20%" y="-20%" width="140%" height="140%">
          <feGaussianBlur stdDeviation="1.5" result="blur" />
          <feMerge>
            <feMergeNode in="blur" />
            <feMergeNode in="SourceGraphic" />
          </feMerge>
        </filter>
      </defs>

      {connections.map((connection, index) => {
        // Use AI-generated path if available, otherwise generate fallback
        const path = connection.path || generateCurvedPath(connection.from, connection.to, connection.type);
        
        return (
          <g key={`connection-${index}`}>
            {/* Shadow/glow path */}
            <path
              d={path}
              fill="none"
              stroke="hsl(var(--muted-foreground))"
              strokeWidth="3"
              strokeOpacity="0.1"
              strokeLinecap="round"
            />
            
            {/* Main path */}
            <path
              d={path}
              fill="none"
              stroke={connection.type === 'child' ? 'url(#childLineGradient)' : 'url(#parentLineGradient)'}
              strokeWidth="2"
              strokeLinecap="round"
              className="transition-all duration-300"
              filter="url(#lineGlow)"
            />
          </g>
        );
      })}
    </svg>
  );
};

// Hook to calculate connection positions
export const useConnectionPositions = (
  containerRef: React.RefObject<HTMLDivElement>,
  memberElements: Map<string, HTMLElement | null>,
  members: any[],
  heartElements: Map<string, HTMLElement | null>
) => {
  const [connections, setConnections] = useState<Connection[]>([]);

  useEffect(() => {
    const calculateConnections = () => {
      if (!containerRef.current) return;
      
      const containerRect = containerRef.current.getBoundingClientRect();
      const newConnections: Connection[] = [];

      // Calculate parent-to-member connections (parent above, member below)
      members.forEach((member) => {
        const memberEl = memberElements.get(member.id);
        if (!memberEl) return;

        const memberRect = memberEl.getBoundingClientRect();
        const memberTop = {
          x: memberRect.left - containerRect.left + memberRect.width / 2,
          y: memberRect.top - containerRect.top,
        };

        // Check for parents-of-X heart element (combined heart for both parents)
        const parentsHeartEl = heartElements.get(`parents-of-${member.id}`);
        if (parentsHeartEl) {
          const heartRect = parentsHeartEl.getBoundingClientRect();
          newConnections.push({
            from: memberTop,
            to: {
              x: heartRect.left - containerRect.left + heartRect.width / 2,
              y: heartRect.top - containerRect.top + heartRect.height,
            },
            type: 'parent',
            fromMemberId: member.id,
            toMemberId: 'parents',
          });
        } else {
          // Find fathers of this member
          const fathers = members.filter(m => 
            m.relation_type === `father_of_${member.id}` || 
            m.relation_type === `father_2_of_${member.id}`
          );

          fathers.forEach((father) => {
            const fatherEl = memberElements.get(father.id);
            if (fatherEl) {
              const fatherRect = fatherEl.getBoundingClientRect();
              newConnections.push({
                from: memberTop,
                to: {
                  x: fatherRect.left - containerRect.left + fatherRect.width / 2,
                  y: fatherRect.top - containerRect.top + fatherRect.height,
                },
                type: 'parent',
                fromMemberId: member.id,
                toMemberId: father.id,
              });
            }
          });

          // Find mothers of this member
          const mothers = members.filter(m => 
            m.relation_type === `mother_of_${member.id}` || 
            m.relation_type === `mother_2_of_${member.id}`
          );

          mothers.forEach((mother) => {
            const motherEl = memberElements.get(mother.id);
            if (motherEl) {
              const motherRect = motherEl.getBoundingClientRect();
              newConnections.push({
                from: memberTop,
                to: {
                  x: motherRect.left - containerRect.left + motherRect.width / 2,
                  y: motherRect.top - containerRect.top + motherRect.height,
                },
                type: 'parent',
                fromMemberId: member.id,
                toMemberId: mother.id,
              });
            }
          });
        }
      });

      // Calculate child connections (from heart to child)
      heartElements.forEach((heartEl, heartKey) => {
        if (!heartEl || heartKey.startsWith('parent-') || heartKey.startsWith('parents-of-')) return;

        const heartRect = heartEl.getBoundingClientRect();
        const heartCenter = {
          x: heartRect.left - containerRect.left + heartRect.width / 2,
          y: heartRect.top - containerRect.top + heartRect.height,
        };

        // The heartKey is the parent member ID
        const parentMemberId = heartKey;

        // Find children of this member
        const childMembers = members.filter(m => 
          m.relation_type.startsWith(`child_of_${parentMemberId}`)
        );

        childMembers.forEach((child) => {
          const childEl = memberElements.get(child.id);
          if (childEl) {
            const childRect = childEl.getBoundingClientRect();
            newConnections.push({
              from: heartCenter,
              to: {
                x: childRect.left - containerRect.left + childRect.width / 2,
                y: childRect.top - containerRect.top,
              },
              type: 'child',
              fromMemberId: parentMemberId,
              toMemberId: child.id,
            });
          }
        });
      });

      setConnections(newConnections);
    };

    // Delay to ensure DOM is rendered
    const timer = setTimeout(calculateConnections, 150);
    
    // Recalculate on resize
    window.addEventListener('resize', calculateConnections);
    
    return () => {
      clearTimeout(timer);
      window.removeEventListener('resize', calculateConnections);
    };
  }, [containerRef, memberElements, members, heartElements]);

  return connections;
};

import { useState, useEffect } from 'react';
import { Dialog, DialogContent, DialogHeader, DialogTitle } from '@/components/ui/dialog';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Avatar, AvatarFallback, AvatarImage } from '@/components/ui/avatar';
import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/components/ui/tabs';
import { ScrollArea } from '@/components/ui/scroll-area';
import { supabase } from '@/integrations/supabase/client';
import { useAuth } from '@/contexts/AuthContext';
import { Search, Users, MessageSquare, UserPlus } from 'lucide-react';
import { StarUsername } from '@/components/user/StarUsername';

interface UserProfile {
  id: string;
  name: string | null;
  username: string | null;
  avatar_url: string | null;
}

interface SendInvitationDialogProps {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  onSelectUser: (userId: string) => void;
}

export const SendInvitationDialog = ({
  open,
  onOpenChange,
  onSelectUser,
}: SendInvitationDialogProps) => {
  const { user } = useAuth();
  const [searchQuery, setSearchQuery] = useState('');
  const [followers, setFollowers] = useState<UserProfile[]>([]);
  const [following, setFollowing] = useState<UserProfile[]>([]);
  const [searchResults, setSearchResults] = useState<UserProfile[]>([]);
  const [isLoading, setIsLoading] = useState(false);

  useEffect(() => {
    if (open && user?.id) {
      fetchFollowData();
    }
  }, [open, user?.id]);

  const fetchFollowData = async () => {
    if (!user?.id) return;

    try {
      // Fetch followers
      const { data: followersData } = await supabase
        .from('follows')
        .select('follower_id')
        .eq('following_id', user.id);

      if (followersData) {
        const followerIds = followersData.map(f => f.follower_id);
        const { data: profiles } = await supabase
          .from('profiles')
          .select('id, name, username, avatar_url')
          .in('id', followerIds);
        setFollowers(profiles || []);
      }

      // Fetch following
      const { data: followingData } = await supabase
        .from('follows')
        .select('following_id')
        .eq('follower_id', user.id);

      if (followingData) {
        const followingIds = followingData.map(f => f.following_id);
        const { data: profiles } = await supabase
          .from('profiles')
          .select('id, name, username, avatar_url')
          .in('id', followingIds);
        setFollowing(profiles || []);
      }
    } catch (error) {
      console.error('Error fetching follow data:', error);
    }
  };

  const handleSearch = async (query: string) => {
    setSearchQuery(query);
    if (query.length < 2) {
      setSearchResults([]);
      return;
    }

    setIsLoading(true);
    try {
      const { data } = await supabase
        .from('profiles')
        .select('id, name, username, avatar_url')
        .or(`name.ilike.%${query}%,username.ilike.%${query}%`)
        .neq('id', user?.id)
        .limit(20);

      setSearchResults(data || []);
    } catch (error) {
      console.error('Error searching users:', error);
    } finally {
      setIsLoading(false);
    }
  };

  const renderUserList = (users: UserProfile[]) => (
    <ScrollArea className="h-[300px]">
      {users.length === 0 ? (
        <p className="text-center text-muted-foreground py-8">Foydalanuvchilar topilmadi</p>
      ) : (
        <div className="space-y-2">
          {users.map((profile) => (
            <button
              key={profile.id}
              className="w-full flex items-center gap-3 p-3 rounded-lg hover:bg-muted transition-colors"
              onClick={() => {
                onSelectUser(profile.id);
                onOpenChange(false);
              }}
            >
              <Avatar className="h-10 w-10">
                <AvatarImage src={profile.avatar_url || undefined} />
                <AvatarFallback className="bg-primary text-primary-foreground">
                  {profile.name?.charAt(0)?.toUpperCase() || 'U'}
                </AvatarFallback>
              </Avatar>
              <div className="text-left flex-1 min-w-0">
                <p className="font-medium truncate">{profile.name || 'Foydalanuvchi'}</p>
                {profile.username && (
                  <div className="truncate">
                    <StarUsername username={profile.username} textClassName="text-sm" />
                  </div>
                )}
              </div>
            </button>
          ))}
        </div>
      )}
    </ScrollArea>
  );

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent className="max-w-md">
        <DialogHeader>
          <DialogTitle>Taklifnoma yuborish</DialogTitle>
        </DialogHeader>

        <div className="space-y-4">
          <div className="relative">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
            <Input
              placeholder="Ism yoki username bo'yicha qidirish..."
              value={searchQuery}
              onChange={(e) => handleSearch(e.target.value)}
              className="pl-10"
            />
          </div>

          {searchQuery.length >= 2 ? (
            <div>
              <p className="text-sm text-muted-foreground mb-2">Qidiruv natijalari</p>
              {isLoading ? (
                <p className="text-center py-8 text-muted-foreground">Qidirilmoqda...</p>
              ) : (
                renderUserList(searchResults)
              )}
            </div>
          ) : (
            <Tabs defaultValue="followers">
              <TabsList className="w-full">
                <TabsTrigger value="followers" className="flex-1">
                  <Users className="h-4 w-4 mr-2" />
                  Kuzatuvchilar
                </TabsTrigger>
                <TabsTrigger value="following" className="flex-1">
                  <UserPlus className="h-4 w-4 mr-2" />
                  Kuzatilmoqda
                </TabsTrigger>
              </TabsList>

              <TabsContent value="followers" className="mt-4">
                {renderUserList(followers)}
              </TabsContent>

              <TabsContent value="following" className="mt-4">
                {renderUserList(following)}
              </TabsContent>
            </Tabs>
          )}
        </div>
      </DialogContent>
    </Dialog>
  );
};

import { useState, useRef, useEffect, useMemo, useCallback } from 'react';

import { createPortal } from 'react-dom';
import { Play, Pause, ChevronLeft, ChevronRight, Heart, X } from 'lucide-react';
import { Post } from '@/types';
import { cn } from '@/lib/utils';
import { useColorExtractor } from '@/hooks/useColorExtractor';
import { FullscreenActions } from '@/components/post/FullscreenActions';
import { MemorialFullscreenActions } from '@/components/post/MemorialFullscreenActions';
import { PostCaption } from '@/components/post/PostCaption';
import { usePostLikes } from '@/hooks/usePostLikes';
import { UserAvatar } from '@/components/user/UserAvatar';
import { UserInfo } from '@/components/user/UserInfo';
import { FollowButton } from '@/components/user/FollowButton';
import { SamsungUltraVideoPlayer } from '@/components/video/SamsungUltraVideoPlayer';
import { Icon } from '@iconify/react';
import { MusicOverlay } from '@/components/music/MusicOverlay';
import { playExclusiveAudio, stopActiveAudio } from '@/lib/audioController';
import { useSavedMusic } from '@/hooks/useSavedMusic';

interface FullScreenViewerProps {
  posts: Post[];
  initialIndex: number;
  onClose: () => void;
}

export const FullScreenViewer = ({ posts, initialIndex, onClose }: FullScreenViewerProps) => {
  const [currentPostIndex, setCurrentPostIndex] = useState(initialIndex);
  const [currentMediaIndex, setCurrentMediaIndex] = useState(0);
  const [isPlaying, setIsPlaying] = useState(true);
  const [isTransitioning, setIsTransitioning] = useState(false);
  const [slideDirection, setSlideDirection] = useState<'up' | 'down' | null>(null);
  const [showDoubleTapHeart, setShowDoubleTapHeart] = useState(false);
  const [heartAnimClass, setHeartAnimClass] = useState('animate-heartBurst');
  const [showVideoPlayer, setShowVideoPlayer] = useState(false);
  const [videoPlayerSrc, setVideoPlayerSrc] = useState('');
  const audioRef = useRef<HTMLAudioElement | null>(null);
  const [isAudioPlaying, setIsAudioPlaying] = useState(false);
  const containerRef = useRef<HTMLDivElement>(null);
  const videoRef = useRef<HTMLVideoElement>(null);

  const touchStartY = useRef(0);
  const touchStartX = useRef(0);
  const lastTapRef = useRef(0);
  const singleTapTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  const currentPost = posts[currentPostIndex];

  const mediaUrls = currentPost?.media_urls || (currentPost?.image_url ? [currentPost.image_url] : []);
  const currentMediaUrl = mediaUrls[currentMediaIndex];

  const rawContent = currentPost?.content || '';
  const locationMatch = rawContent.match(/(?:^|\n)📍\s*(.+?)\s*$/m);
  const locationLine = locationMatch ? locationMatch[1].trim() : '';
  const locationParts = locationLine.split('||').map((p) => p.trim()).filter(Boolean);
  const locationText = locationParts[0] || '';
  const coordsPart = locationParts[1] || '';
  const coordsMatch = coordsPart.match(/^(-?\d+(?:\.\d+)?),\s*(-?\d+(?:\.\d+)?)$/);
  const lat = coordsMatch?.[1] || '';
  const lon = coordsMatch?.[2] || '';
  const mapUrl = locationText
    ? lat && lon
      ? 'https://www.google.com/maps?q=' + encodeURIComponent(lat + ',' + lon)
      : 'https://www.google.com/maps/search/?api=1&query=' + encodeURIComponent(locationText)
    : '';

  const formatLocationShort = (text: string) => {
    const normalized = (text || '').trim();
    if (!normalized) return '';

    const parts = normalized
      .split(',')
      .map((p) => p.trim())
      .filter(Boolean);

    const drop = new Set(["o'zbekiston", 'ozbekiston', 'uzbekistan', 'republic of uzbekistan']);
    let cleaned = parts;
    if (cleaned.length > 1) {
      const last = cleaned[cleaned.length - 1].toLowerCase();
      if (drop.has(last)) cleaned = cleaned.slice(0, -1);
    }

    const mostSpecific = cleaned[0] || cleaned[cleaned.length - 1] || '';
    const oneWord = mostSpecific.split(/\s+/).filter(Boolean)[0] || '';
    return oneWord;
  };

  const locationTextShort = formatLocationShort(locationText);
  const contentWithoutLocation = rawContent.replace(/(?:\n|^)📍\s*.+\s*$/m, '').trim();

  // Hook for double-tap like
  const { isLiked, toggleLike } = usePostLikes(currentPost?.id || '');

  const { isSaved, save, unsave } = useSavedMusic();

  const audioKey = currentPost?.id ? `post:${currentPost.id}:fullscreen` : null;

  const stopAudio = useCallback(() => {
    const el = audioRef.current;
    if (!el) return;
    try {
      el.pause();
    } catch {
      // ignore
    }
    setIsAudioPlaying(false);
  }, []);

  const playAudio = useCallback(async () => {
    if (!currentPost?.audio_url) return;
    if (!audioKey) return;
    const el = audioRef.current;
    if (!el) return;

    try {
      el.src = currentPost.audio_url;
      el.loop = true;
      el.preload = 'auto';
      el.crossOrigin = 'anonymous';
      try { el.load(); } catch (_e) { /* ignore load errors */ }
    } catch {
      // ignore
    }

    const ok = await playExclusiveAudio(audioKey, el);
    if (!ok) {
      setIsAudioPlaying(false);
      return;
    }
    setIsAudioPlaying(!el.paused);
  }, [audioKey, currentPost?.audio_url]);

  const toggleAudio = useCallback(() => {
    const el = audioRef.current;
    if (!el) return;
    if (isAudioPlaying) {
      stopActiveAudio(audioKey || undefined);
      stopAudio();
    } else {
      void playAudio();
    }
  }, [audioKey, isAudioPlaying, playAudio, stopAudio]);

  const isVideo = (url: string) => {
    return url?.includes('.mp4') || url?.includes('.mov') || url?.includes('.webm');
  };

  // Extract dominant colors from current media
  const { dominantColor, secondaryColor } = useColorExtractor(
    currentMediaUrl,
    isVideo(currentMediaUrl || '')
  );

  const isLowPowerDevice = useMemo(() => {
    if (typeof window === 'undefined') return false;
    try {
      const isSmallScreen = window.matchMedia?.('(max-width: 768px)')?.matches ?? false;
      const cores = typeof navigator !== 'undefined' ? (navigator as Navigator & { hardwareConcurrency?: number }).hardwareConcurrency : undefined;
      const lowCpu = typeof cores === 'number' ? cores <= 6 : false;
      return isSmallScreen || lowCpu;
    } catch {
      return false;
    }
  }, []);

  useEffect(() => {
    setCurrentMediaIndex(0);
    setIsPlaying(true);
    stopActiveAudio(audioKey || undefined);
    stopAudio();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [currentPostIndex]);

  useEffect(() => {
    return () => {
      stopActiveAudio(audioKey || undefined);
      stopAudio();
    };
  }, [audioKey, stopAudio]);

  useEffect(() => {
    if (videoRef.current) {
      if (isPlaying) {
        videoRef.current.play().catch(() => {});
      } else {
        videoRef.current.pause();
      }
    }
  }, [isPlaying, currentMediaIndex, currentPostIndex]);

  // Smooth transition to next/prev post
  const smoothNavigate = (direction: 'up' | 'down') => {
    if (isTransitioning) return;

    const canGoNext = direction === 'down' && currentPostIndex < posts.length - 1;
    const canGoPrev = direction === 'up' && currentPostIndex > 0;

    if (!canGoNext && !canGoPrev) return;

    setIsTransitioning(true);
    setSlideDirection(direction);

    // Wait for exit animation
    setTimeout(() => {
      if (direction === 'down') {
        setCurrentPostIndex((prev) => prev + 1);
      } else {
        setCurrentPostIndex((prev) => prev - 1);
      }

      // Reset for enter animation
      setTimeout(() => {
        setSlideDirection(null);
        setIsTransitioning(false);
      }, 300);
    }, 200);
  };

  const handleClose = useCallback(() => {
    stopActiveAudio(audioKey || undefined);
    stopAudio();
    onClose();
  }, [audioKey, onClose, stopAudio]);

  // Mouse wheel scroll for post navigation with debounce
  useEffect(() => {
    const container = containerRef.current;
    if (!container) return;

    let isScrolling = false;
    let scrollTimeout: ReturnType<typeof setTimeout>;

    const handleWheel = (e: WheelEvent) => {
      e.preventDefault();

      if (isScrolling || isTransitioning) return;

      if (Math.abs(e.deltaY) > 30) {
        isScrolling = true;

        if (e.deltaY > 0) {
          smoothNavigate('down');
        } else {
          smoothNavigate('up');
        }

        // Block scrolling for 600ms (animation duration + buffer)
        scrollTimeout = setTimeout(() => {
          isScrolling = false;
        }, 600);
      }
    };

    container.addEventListener('wheel', handleWheel, { passive: false });
    return () => {
      container.removeEventListener('wheel', handleWheel);
      clearTimeout(scrollTimeout);
    };
  }, [posts.length, isTransitioning, currentPostIndex]);

  // Handle keyboard navigation
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.key === 'Escape') handleClose();
      if (e.key === 'ArrowUp') smoothNavigate('up');
      if (e.key === 'ArrowDown') smoothNavigate('down');
      if (e.key === 'ArrowLeft') goToPrevMedia();
      if (e.key === 'ArrowRight') goToNextMedia();
      if (e.key === ' ') togglePlay();
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [currentPostIndex, currentMediaIndex, handleClose]);

  // Prevent body scroll
  useEffect(() => {
    document.body.style.overflow = 'hidden';
    return () => {
      document.body.style.overflow = '';
    };
  }, []);

  const goToNextPost = () => {
    smoothNavigate('down');
  };

  const goToPrevPost = () => {
    smoothNavigate('up');
  };

  const goToNextMedia = () => {
    if (currentMediaIndex < mediaUrls.length - 1) {
      setCurrentMediaIndex((prev) => prev + 1);
    }
  };

  const goToPrevMedia = () => {
    if (currentMediaIndex > 0) {
      setCurrentMediaIndex((prev) => prev - 1);
    }
  };

  const togglePlay = () => {
    setIsPlaying((prev) => !prev);
  };

  // Touch handlers for swipe
  const handleTouchStart = (e: React.TouchEvent) => {
    touchStartY.current = e.touches[0].clientY;
    touchStartX.current = e.touches[0].clientX;
  };

  const handleTouchEnd = (e: React.TouchEvent) => {
    const touchEndY = e.changedTouches[0].clientY;
    const touchEndX = e.changedTouches[0].clientX;
    const diffY = touchStartY.current - touchEndY;
    const diffX = touchStartX.current - touchEndX;

    // Prioritize vertical swipe for post navigation
    if (Math.abs(diffY) > Math.abs(diffX) && Math.abs(diffY) > 50) {
      if (diffY > 0) {
        goToNextPost();
      } else {
        goToPrevPost();
      }
    }
    // Horizontal swipe
    else if (Math.abs(diffX) > 50) {
      if (diffX > 0) {
        goToNextPost();
      } else {
        goToPrevPost();
      }
    }
  };

  const handleMediaClick = (e: React.MouseEvent) => {
    const now = Date.now();
    const DOUBLE_TAP_DELAY = 300;

    // Check for double tap
    if (now - lastTapRef.current < DOUBLE_TAP_DELAY) {
      if (singleTapTimerRef.current) {
        clearTimeout(singleTapTimerRef.current);
        singleTapTimerRef.current = null;
      }
      // Double tap detected - show heart and like
      const anims = ['animate-heartBurst', 'animate-likePop', 'animate-likeSwing', 'animate-likeFloat', 'animate-likePulse'];
      setHeartAnimClass(anims[Math.floor(Math.random() * anims.length)]);
      setShowDoubleTapHeart(true);
      if (!isLiked) {
        toggleLike();
      }
      setTimeout(() => setShowDoubleTapHeart(false), 1000);
      lastTapRef.current = 0;
      return;
    }

    lastTapRef.current = now;

    const rect = e.currentTarget.getBoundingClientRect();
    const x = e.clientX - rect.left;
    const width = rect.width;

    // Single tap logic - delayed to check for double tap
    if (singleTapTimerRef.current) clearTimeout(singleTapTimerRef.current);
    singleTapTimerRef.current = setTimeout(() => {
      if (lastTapRef.current === 0) return;
      lastTapRef.current = 0;
      singleTapTimerRef.current = null;

      // Click on left side - previous media, right side - next media, center - toggle play
      if (x < width * 0.3 && mediaUrls.length > 1) {
        goToPrevMedia();
      } else if (x > width * 0.7 && mediaUrls.length > 1) {
        goToNextMedia();
      } else if (isVideo(currentMediaUrl)) {
        togglePlay();
      }
    }, DOUBLE_TAP_DELAY + 50);
  };

  useEffect(() => {
    return () => {
      if (singleTapTimerRef.current) {
        clearTimeout(singleTapTimerRef.current);
        singleTapTimerRef.current = null;
      }
    };
  }, []);

  if (!currentPost) return null;

  return (
    <>
      <div
        ref={containerRef}
        className="fixed inset-0 z-[60] flex flex-col overflow-hidden"
        style={{
          backgroundColor: '#000',
          backgroundImage: `linear-gradient(135deg, ${dominantColor} 0%, ${secondaryColor} 50%, ${dominantColor} 100%)`
        }}
        onTouchStart={handleTouchStart}
        onTouchEnd={handleTouchEnd}>

        {/* Blurred background overlay for extra depth */}
        {!isLowPowerDevice && (
          <div
            className="absolute inset-0 z-0"
            style={{
              background: `radial-gradient(ellipse at center, transparent 0%, ${dominantColor} 70%)`,
              backdropFilter: 'blur(20px)'
            }}
          />
        )}

        {/* Header */}
        <div className="absolute top-0 left-0 right-0 z-10 flex items-center justify-between p-4 bg-transparent">
          <button
            onClick={handleClose}
            className="p-3.5 rounded-full bg-white/10 backdrop-blur-md border border-white/10 opacity-100 mx-px text-center px-[4px] py-[4px]"
            aria-label="Close"
            type="button">

            <X className="text-white w-[20px] h-[20px]" />
          </button>

          {/* Post counter */}
        </div>

        {/* Media area */}
        <div
          className={cn(
            "flex-1 flex items-center justify-center relative overflow-hidden z-[1] transition-all duration-300 ease-out",
            slideDirection === 'down' && "animate-slide-out-up",
            slideDirection === 'up' && "animate-slide-out-down",
            !slideDirection && "animate-slide-in"
          )}
          onClick={handleMediaClick}>

          {isVideo(currentMediaUrl) ?
            <>
              <video
                ref={videoRef}
                src={currentMediaUrl}
                className="max-w-full max-h-full object-contain"
                loop
                playsInline
                autoPlay />

              {/* Play/Pause overlay */}
              <button
                onClick={(e) => { e.stopPropagation(); togglePlay(); }}
                className="absolute inset-0 flex items-center justify-center">

                <div className={cn(
                  "p-4 rounded-full bg-black/30 backdrop-blur-sm transition-opacity",
                  isPlaying ? "opacity-0" : "opacity-100"
                )}>
                  {isPlaying ?
                    <Pause className="h-8 w-8 text-white" /> :
                    <Play className="h-8 w-8 text-white" />
                  }
                </div>
              </button>
            </> :

            <img
              src={currentMediaUrl}
              alt="Post media"
              className="max-w-full max-h-full object-contain" />

          }

          {/* Double-tap heart animation overlay */}
          {showDoubleTapHeart &&
            <div className="absolute inset-0 flex items-center justify-center pointer-events-none z-20">
              <Heart className={cn("h-24 w-24 text-white fill-white drop-shadow-lg", heartAnimClass)} />
            </div>
          }

          {/* Media indicators */}
          {mediaUrls.length > 1 &&
            <>
              {/* Dots */}
              <div className="absolute bottom-24 left-1/2 -translate-x-1/2 flex gap-1.5">
                {mediaUrls.map((_, index) =>
                  <button
                    key={index}
                    onClick={(e) => { e.stopPropagation(); setCurrentMediaIndex(index); }}
                    className={cn(
                      "w-2 h-2 rounded-full transition-colors",
                      currentMediaIndex === index ? "bg-white" : "bg-white/40"
                    )} />

                )}
              </div>

              {/* Navigation arrows */}
              {currentMediaIndex > 0 &&
                <button
                  onClick={(e) => { e.stopPropagation(); goToPrevMedia(); }}
                  className="absolute left-2 top-1/2 -translate-y-1/2 p-2 bg-black/30 backdrop-blur-sm px-px py-[5px] border-0 rounded-2xl opacity-85 text-left text-sm mx-0 my-0">

                  <ChevronLeft className="h-5 text-white w-[9px]" />
                </button>
              }
              {currentMediaIndex < mediaUrls.length - 1 &&
                <button
                  onClick={(e) => { e.stopPropagation(); goToNextMedia(); }}
                  className="absolute right-2 top-1/2 -translate-y-1/2 p-2 bg-black/30 backdrop-blur-sm opacity-85 px-px py-[5px] rounded-sm">

                  <ChevronRight className="h-5 text-white w-[10px] shadow-2xs opacity-100 px-px py-[5px]" />
                </button>
              }
            </>
          }
        </div>

        {currentPost.audio_url && (
          <div className="absolute bottom-6 right-4 z-30" onClick={(e) => e.stopPropagation()}>
            <MusicOverlay
              audioTitle={currentPost.audio_title}
              audioArtist={currentPost.audio_artist}
              isPlaying={isAudioPlaying}
              isSaved={isSaved(currentPost.audio_url)}
              onTogglePlay={toggleAudio}
              onToggleSave={() => {
                if (!currentPost.audio_url) return;
                if (isSaved(currentPost.audio_url)) {
                  void unsave(currentPost.audio_url);
                } else {
                  void save({
                    audio_url: currentPost.audio_url,
                    audio_title: currentPost.audio_title,
                    audio_artist: currentPost.audio_artist,
                  });
                }
              }}
            />

            <audio
              ref={audioRef}
              preload="none"
              onPlay={() => setIsAudioPlaying(true)}
              onPause={() => setIsAudioPlaying(false)}
              onEnded={() => setIsAudioPlaying(false)}
              className="absolute left-0 top-0 h-px w-px opacity-0 pointer-events-none"
            />
          </div>
        )}

        {/* Right side actions - vertical layout like reference */}
        <div className="absolute right-4 bottom-32 z-[2]">
          {currentPost.is_memorial ? (
            <MemorialFullscreenActions
              memorialPostId={currentPost.id}
              initialLikesCount={currentPost.likes_count}
              initialCommentsCount={currentPost.comments_count}
              initialViewsCount={currentPost.views_count ?? 0}
            />
          ) : (
            <FullscreenActions
              postId={currentPost.id}
              initialLikesCount={currentPost.likes_count}
              initialCommentsCount={currentPost.comments_count}
              initialViewsCount={currentPost.views_count ?? 0}
              videoUrl={isVideo(currentMediaUrl) ? currentMediaUrl : undefined}
              onOpenVideoPlayer={(url) => {
                setVideoPlayerSrc(url);
                setShowVideoPlayer(true);
                if (videoRef.current) videoRef.current.pause();
                setIsPlaying(false);
                stopActiveAudio(audioKey || undefined);
                stopAudio();
              }} 
            />
          )}
        </div>

        {/* Author info */}
        <div className="absolute bottom-14 left-0 right-14 bg-transparent p-4 pt-14 z-[1]">
          {!currentPost.is_memorial && (
            <div className="flex items-center mb-2 gap-2">
              <UserAvatar userId={currentPost.user_id} avatarUrl={currentPost.author?.avatar_url} name={currentPost.author?.full_name} size="lg" className="border-2 border-white/20 ring-0" />
              <UserInfo userId={currentPost.user_id} name={currentPost.author?.full_name} username={currentPost.author?.username} variant="fullscreen" />
              <FollowButton targetUserId={currentPost.user_id} size="sm" />
            </div>
          )}
          {locationTextShort && mapUrl && !currentPost.is_memorial && (
            <a
              href={mapUrl}
              target="_blank"
              rel="noreferrer"
              className="inline-flex items-center gap-1 text-xs text-white/70 font-medium uppercase max-w-[80%] hover:text-white transition-colors"
              title={locationText}
            >
              <Icon icon="gis:location-poi" className="h-3.5 w-3.5 flex-shrink-0" />
              <span className="truncate">{locationTextShort}</span>
            </a>
          )}

          {contentWithoutLocation && <PostCaption content={contentWithoutLocation} variant="fullscreen" />}
        </div>
      </div>

      {typeof document !== 'undefined' && showVideoPlayer && createPortal(
        <div
          className="fixed inset-0 z-[80] w-full h-full min-h-[100dvh] overflow-hidden bg-black"
          style={{ height: '100dvh', maxHeight: '100dvh' }}>

          <SamsungUltraVideoPlayer
            src={videoPlayerSrc}
            title={currentPost?.content?.slice(0, 50) || 'Video'}
            onClose={() => {
              setShowVideoPlayer(false);
            }}
            startInFullscreen={true}
          />
        </div>,
        document.body
      )}
    </>
  );
};

import { useState, useRef, useEffect, useCallback, useMemo } from 'react';

