              userId={currentPost.user_id}

              avatarUrl={currentPost.author?.avatar_url}

              name={currentPost.author?.full_name}

              size="lg"

              className="border-2 border-white/20 ring-0"

              hasStory={!!getStoryInfo(currentPost.user_id)}

              storyRingId={getStoryInfo(currentPost.user_id)?.ring_id}

              hasUnviewedStory={getStoryInfo(currentPost.user_id)?.has_unviewed}

              onStoryClick={() => openStoriesForUser(currentPost.user_id)} />



            <UserInfo userId={currentPost.user_id} name={currentPost.author?.full_name} username={currentPost.author?.username} variant="fullscreen" />

            <FollowButton targetUserId={currentPost.user_id} size="sm" />

          </div>

          {activeTab === 'posts' && locationTextShort && mapUrl && (

            <a

              href={mapUrl}

              target="_blank"

              rel="noreferrer"

              className="inline-flex items-center gap-1 text-xs text-white/70 font-medium uppercase max-w-[80%] hover:text-white transition-colors"

              title={locationText}

            >

              <Icon icon="gis:location-poi" className="h-3.5 w-3.5 flex-shrink-0" />

              <span className="truncate">{locationTextShort}</span>

            </a>

          )}



          {postContentWithoutLocation && <PostCaption content={postContentWithoutLocation} variant="fullscreen" />}

        </div>

      </>);

  };



  const fetchStoryGroupForUser = useCallback(async (targetUserId: string): Promise<StoryGroup | null> => {

    try {

      const { data: stories, error } = await supabase.

      from('stories').

      select('*').

      eq('user_id', targetUserId).

      gt('expires_at', new Date().toISOString()).

      order('created_at', { ascending: true });



      if (error) throw error;

      if (!stories || stories.length === 0) return null;



      const { data: profiles } = await supabase.

      from('profiles').

      select('id, name, username, avatar_url').

      in('id', [targetUserId]);



      const authorProfile = profiles?.find((p) => p.id === targetUserId);

      const viewerId = user?.id;



      const [viewsRes, likesRes] = await Promise.all([

      viewerId ?

      supabase.from('story_views').select('story_id').eq('viewer_id', viewerId).in('story_id', stories.map((s) => s.id)) :

      Promise.resolve({ data: [] as Record<string, unknown>[] }),

      viewerId ?

      supabase.from('story_likes').select('story_id').eq('user_id', viewerId).in('story_id', stories.map((s) => s.id)) :

      Promise.resolve({ data: [] as Record<string, unknown>[] })]

      );



      const viewsResData = viewsRes && 'data' in viewsRes ? (viewsRes.data as { story_id: string }[]) : [];

      const likesResData = likesRes && 'data' in likesRes ? (likesRes.data as { story_id: string }[]) : [];



      const viewedStoryIds = new Set(viewsResData?.map(v => v.story_id) || []);

      const likedStoryIds = new Set(likesResData?.map(l => l.story_id) || []);



      const normalizedStories = stories.map((s: Record<string, unknown>) => ({

        ...s,

        media_type: s.media_type as 'image' | 'video',

        ring_id: (s.ring_id as string) || 'default',

        author: authorProfile ? {

          id: authorProfile.id,

          name: authorProfile.name || '',

          username: authorProfile.username || '',

          avatar_url: authorProfile.avatar_url || ''

        } : undefined,

        has_viewed: viewerId ? viewedStoryIds.has(s.id as string) : false,

        has_liked: viewerId ? likedStoryIds.has(s.id as string) : false

      } as unknown as Story));



      return {

        user_id: targetUserId,

        user: authorProfile || { id: targetUserId, name: null, username: null, avatar_url: null },

        stories: normalizedStories,

        has_unviewed: normalizedStories.some((s) => !s.has_viewed)

      };

    } catch (err) {

      console.error('Error fetching user stories:', err);

      return null;

    }

  }, [user?.id]);



  const openStoriesForUser = useCallback(async (targetUserId: string) => {

    const g = await fetchStoryGroupForUser(targetUserId);

    if (!g) return;

    setStoryViewerGroups([g]);

    setStoryViewerOpen(true);

  }, [fetchStoryGroupForUser]);



  useEffect(() => {

    return () => {

      stopActiveAudio(audioKey || undefined);

      stopAudio();

    };

  }, [audioKey, stopAudio]);



  return (

    <>

      <div

        ref={containerRef}

        className="fixed inset-0 z-[60] flex flex-col overflow-hidden touch-none"

        style={{

          backgroundColor: '#000',

          ...bgStyle

        }}

        onMouseDown={handleMouseDown}

        onMouseUp={handleMouseUp}

        onTouchStart={(e) => {

          ensureAmbientPlayback();

          touchMoved.current = false;

          touchStartY.current = e.touches[0].clientY;

          touchStartX.current = e.touches[0].clientX;

          touchStartTime.current = Date.now();

        }}

        onTouchMove={(e) => {

          const diffY = Math.abs(touchStartY.current - e.touches[0].clientY);

          const diffX = Math.abs(touchStartX.current - e.touches[0].clientX);

          if (diffY > 8 || diffX > 8) touchMoved.current = true;

        }}

        onTouchEnd={(e) => {

          const diffY = touchStartY.current - e.changedTouches[0].clientY;

          const diffX = touchStartX.current - e.changedTouches[0].clientX;

          const elapsed = Date.now() - touchStartTime.current;

          const velocityY = Math.abs(diffY) / Math.max(elapsed, 1);

          // If swiping on shorts, we prefer the internal YT overlay's own logic?

          // No, actually, the global handler is fine too.

          // Just make sure it doesn't duplicate if shorts internal overlay is still there.

          // Lower threshold for faster swipes — feels more responsive

          const threshold = velocityY > 0.25 ? 16 : 34;



          if (Math.abs(diffY) > Math.abs(diffX) && Math.abs(diffY) > threshold) {

            smoothNavigate(diffY > 0 ? 'down' : 'up');

          } else if (Math.abs(diffX) > 50) {

            // Horizontal swipe mapping as per legacy FullScreenViewer

            smoothNavigate(diffX > 0 ? 'down' : 'up');

          }

        }}>



        {ambientUrl &&

        <div className="absolute inset-0 z-0 overflow-hidden pointer-events-none">

            <div className="absolute inset-0">

              {activeTab === 'posts' && isVideo(ambientUrl) ?

            <video

              key={ambientUrl}

              ref={ambientVideoRef}

              src={ambientUrl}

              className="absolute inset-0 w-full h-full object-cover"

              style={{

                filter: 'blur(16px) saturate(145%) brightness(0.92) contrast(1.05)',

                transform: 'scale(1.08)',

                opacity: 0.72

              }}

              muted

              playsInline

              autoPlay

              loop

              preload="metadata"

              controls={false}

              disablePictureInPicture /> :





            <img

              key={ambientUrl}

              src={ambientUrl}

              alt=""

              className="absolute inset-0 w-full h-full object-cover"

              style={{

                filter: 'blur(16px) saturate(145%) brightness(0.92) contrast(1.05)',

                transform: 'scale(1.08)',

                opacity: 0.72

              }} />



            }



              <div className="absolute inset-0 bg-black/28" />

              <div className="absolute inset-0 bg-gradient-to-b from-black/45 via-transparent to-black/55" />

              <div

              className="absolute inset-[-10%]"

              style={{

                background:

                'radial-gradient(ellipse at center, rgba(0,0,0,0.06) 0%, rgba(0,0,0,0.38) 58%, rgba(0,0,0,0.72) 100%)'

              }} />

            

            </div>

          </div>

        }



        {activeTab === 'posts' && dominantColor &&

        <div className="absolute inset-0 z-0" style={{

          background: `radial-gradient(ellipse at center, transparent 0%, ${dominantColor} 70%)`,

          backdropFilter: 'blur(20px)'

        }} />

        }



        {/* Top bar with tabs */}

        <div className="absolute top-0 left-0 right-0 z-10 flex items-center justify-between px-3 pt-[env(safe-area-inset-top,10px)] pb-2 bg-gradient-to-b from-black/50 to-transparent">

          <button onClick={handleClose} className="p-1.5 rounded-full bg-white/10 backdrop-blur-md border border-white/10 my-0">

            <X className="w-4 h-4 text-white" />

          </button>



          <div className="flex gap-0.5 bg-white/10 backdrop-blur-md rounded-full p-0.5 border border-white/10 py-[2px] my-[23px]">

            <button

              onClick={() => handleTabSwitch('shorts')}

              className={cn(

                "px-3.5 py-1 rounded-full text-[11px] font-medium transition-all",

                activeTab === 'shorts' ? "bg-white/20 text-white shadow-sm" : "text-white/50 hover:text-white/70"

              )}>

              yt shorts

            </button>

            <button

              onClick={() => handleTabSwitch('posts')}

              className={cn(

                "px-3.5 py-1 rounded-full text-[11px] font-medium transition-all",

                activeTab === 'posts' ? "bg-white/20 text-white shadow-sm" : "text-white/50 hover:text-white/70"

              )}>

              postlar

            </button>

          </div>



          <div className="w-7" />

        </div>



        {/* Content */}

        {activeTab === 'shorts' ? renderShort() : renderPost()}

      </div>



      {typeof document !== 'undefined' && showVideoPlayer && createPortal(

        <div className="fixed inset-0 z-[80] w-full h-full min-h-[100dvh] overflow-hidden bg-black" style={{ height: '100dvh' }}>

          <SamsungUltraVideoPlayer

            src={videoPlayerSrc}

            title={currentPost?.content?.slice(0, 50) || 'Video'}

            onClose={() => setShowVideoPlayer(false)}

            startInFullscreen={true}

          />



        </div>,

        document.body

      )}



      {storyViewerOpen && storyViewerGroups.length > 0 &&

      <StoryViewer

        storyGroups={storyViewerGroups}

        initialGroupIndex={0}

        onClose={() => setStoryViewerOpen(false)} />



      }

    </>);



};

import { useState, useEffect } from 'react';
import { supabase } from '@/integrations/supabase/client';
import { useAuth } from '@/contexts/AuthContext';
import { Sheet, SheetContent, SheetHeader, SheetTitle } from "@/components/ui/sheet";
import { ScrollArea } from "@/components/ui/scroll-area";
import { Input } from "@/components/ui/input";
import { Avatar, AvatarFallback, AvatarImage } from "@/components/ui/avatar";
import { Button } from "@/components/ui/button";
import { Checkbox } from "@/components/ui/checkbox";
import { Label } from '@/components/ui/label';
import { Textarea } from '@/components/ui/textarea';
import { StarUsername } from '@/components/user/StarUsername';
import { toast } from 'sonner';
import { Camera, Users, Megaphone, Crown, UserMinus, UserPlus, Link, Copy, Check, Trash2, Search, RefreshCw } from 'lucide-react';
import { useNavigate } from 'react-router-dom';
import { Dialog, DialogContent, DialogHeader, DialogTitle } from '@/components/ui/dialog';

interface GroupMember {
  id: string;
  user_id: string;
  role: string;
  profile?: {
    id: string;
    name: string | null;
    username: string | null;
    avatar_url: string | null;
  };
}

interface GroupInfo {
  id: string;
  name: string;
  description: string | null;
  avatar_url: string | null;
  type: 'group' | 'channel';
  visibility: 'public' | 'private';
  owner_id: string;
  invite_link: string | null;
}

interface GroupSettingsSheetProps {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  groupInfo: GroupInfo;
  onGroupUpdated: () => void;
}

export const GroupSettingsSheet = ({ open, onOpenChange, groupInfo, onGroupUpdated }: GroupSettingsSheetProps) => {
  const { user } = useAuth();
  const navigate = useNavigate();
  const [name, setName] = useState(groupInfo.name);
  const [description, setDescription] = useState(groupInfo.description || '');
  const [avatarUrl, setAvatarUrl] = useState(groupInfo.avatar_url || '');
  const [isUpdating, setIsUpdating] = useState(false);
  const [members, setMembers] = useState<GroupMember[]>([]);
  const [isLoadingMembers, setIsLoadingMembers] = useState(false);
  const [linkCopied, setLinkCopied] = useState(false);
  const [isGeneratingLink, setIsGeneratingLink] = useState(false);
  const [addMemberOpen, setAddMemberOpen] = useState(false);

  const isOwner = groupInfo.owner_id === user?.id;

  useEffect(() => {
    if (open) {
      setName(groupInfo.name);
      setDescription(groupInfo.description || '');
      setAvatarUrl(groupInfo.avatar_url || '');
      fetchMembers();
    }
  }, [open, groupInfo]);

  const fetchMembers = async () => {
    setIsLoadingMembers(true);
    try {
      const { data: membersData } = await supabase
        .from('group_members').select('*').eq('group_id', groupInfo.id);
      if (membersData) {
        const userIds = membersData.map(m => m.user_id);
        const { data: profiles } = await supabase
          .from('profiles').select('id, name, username, avatar_url').in('id', userIds);
        const profileMap = new Map(profiles?.map(p => [p.id, p]) || []);
        setMembers(membersData.map(m => ({ ...m, profile: profileMap.get(m.user_id) })));
      }
    } catch (error) {
      console.error('Error fetching members:', error);
    } finally {
      setIsLoadingMembers(false);
    }
  };

  const handleAvatarUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    try {
      const fileExt = file.name.split('.').pop();
      const filePath = `${groupInfo.id}.${fileExt}`;
      const { error: uploadError } = await supabase.storage.from('group-avatars').upload(filePath, file, { upsert: true });
      if (uploadError) throw uploadError;
      const { data: { publicUrl } } = supabase.storage.from('group-avatars').getPublicUrl(filePath);
      setAvatarUrl(publicUrl);
    } catch (error) {
      toast.error('Rasm yuklanmadi');
    }
  };

  const handleUpdate = async () => {
    if (!name.trim()) { toast.error('Nomni kiriting'); return; }
    setIsUpdating(true);
    try {
      const { error } = await supabase.from('group_chats')
        .update({ name: name.trim(), description: description.trim() || null, avatar_url: avatarUrl || null })
        .eq('id', groupInfo.id);
      if (error) throw error;
      toast.success('Ma\'lumotlar yangilandi');
      onGroupUpdated();
      onOpenChange(false);
    } catch (error) {
      toast.error('Xatolik yuz berdi');
    } finally {
      setIsUpdating(false);
    }
  };

  const handleRemoveMember = async (memberId: string) => {
    try {
      const { error } = await supabase.from('group_members').delete().eq('id', memberId);
      if (error) throw error;
      toast.success('A\'zo o\'chirildi');
      fetchMembers();
      onGroupUpdated();
    } catch { toast.error('Xatolik yuz berdi'); }
  };

  const handleDeleteGroup = async () => {
    if (!confirm(`${groupInfo.type === 'group' ? 'Guruh' : 'Kanal'}ni o'chirishni xohlaysizmi?`)) return;
    try {
      await supabase.from('group_messages').delete().eq('group_id', groupInfo.id);
      await supabase.from('group_members').delete().eq('group_id', groupInfo.id);
      const { error } = await supabase.from('group_chats').delete().eq('id', groupInfo.id);
      if (error) throw error;
      toast.success(`${groupInfo.type === 'group' ? 'Guruh' : 'Kanal'} o'chirildi`);
      navigate('/messages');
    } catch { toast.error('Xatolik yuz berdi'); }
  };

  const handleMembersAdded = async (userIds: string[]) => {
    if (userIds.length === 0) return;
    try {
      const existingIds = members.map(m => m.user_id);
      const newIds = userIds.filter(id => !existingIds.includes(id) && id !== groupInfo.owner_id);
      if (newIds.length === 0) { toast.info('Bu foydalanuvchilar allaqachon a\'zo'); return; }
      const inserts = newIds.map(uid => ({ group_id: groupInfo.id, user_id: uid, role: 'member' }));
      const { error } = await supabase.from('group_members').upsert(inserts as any, { onConflict: 'group_id,user_id' });
      if (error) throw error;
      toast.success(`${newIds.length} ta a'zo qo'shildi`);
      fetchMembers();
      onGroupUpdated();
    } catch (e: any) {
      toast.error(e?.message || 'Xatolik yuz berdi');
    }
    setAddMemberOpen(false);
  };

  const copyInviteLink = async () => {
    if (!groupInfo.invite_link) return;
    const baseUrl = (import.meta as any).env?.VITE_PUBLIC_APP_URL || window.location.origin;
    const fullLink = `${String(baseUrl).replace(/\/$/, '')}/join/${groupInfo.invite_link}`;
    await navigator.clipboard.writeText(fullLink);
    setLinkCopied(true);
    toast.success('Havola nusxalandi');
    setTimeout(() => setLinkCopied(false), 2000);
  };

  const generateInviteLink = async () => {
    if (!isOwner) return;
    if (groupInfo.invite_link) return;
    setIsGeneratingLink(true);
    try {
      const newLink = `${groupInfo.type}_${Date.now().toString(36)}`;
      const { error } = await supabase.from('group_chats').update({ invite_link: newLink }).eq('id', groupInfo.id);
      if (error) throw error;
      toast.success('Havola yaratildi');
      onGroupUpdated();
    } catch (e: any) {
      toast.error(e?.message || 'Xatolik yuz berdi');
    } finally {
      setIsGeneratingLink(false);
    }
  };

  const revokeInviteLink = async () => {
    if (!isOwner) return;
    if (!confirm("Rostdan ham havolani bekor qilmoqchimisiz? Eski havola endi ishlamaydi.")) return;
    setIsGeneratingLink(true);
    try {
      const { error } = await supabase.from('group_chats').update({ invite_link: null }).eq('id', groupInfo.id);
      if (error) throw error;
      toast.success('Havola bekor qilindi');
      onGroupUpdated();
    } catch (e: any) {
      toast.error(e?.message || 'Xatolik yuz berdi');
    } finally {
      setIsGeneratingLink(false);
    }
  };

  const getInitials = (name: string | null | undefined) => {
    if (!name) return 'U';
    return name.split(' ').map(n => n[0]).join('').toUpperCase().slice(0, 2);
  };

  // Owner profile
  const [ownerProfile, setOwnerProfile] = useState<{ name: string | null; username: string | null; avatar_url: string | null } | null>(null);
  useEffect(() => {
    if (open && groupInfo.owner_id) {
      supabase.from('profiles').select('name, username, avatar_url').eq('id', groupInfo.owner_id).single()
        .then(({ data }) => { if (data) setOwnerProfile(data); });
    }
  }, [open, groupInfo.owner_id]);

  return (
    <>
      <Sheet open={open} onOpenChange={onOpenChange}>
        <SheetContent side="right" className="w-full sm:max-w-md p-0">
          <SheetHeader className="p-4 border-b border-border/50">
            <SheetTitle className="text-lg">
              {groupInfo.type === 'group' ? 'Guruh sozlamalari' : 'Kanal sozlamalari'}
            </SheetTitle>
          </SheetHeader>

          <ScrollArea className="h-[calc(100vh-80px)]">
            <div className="p-5 space-y-6">
              {/* Avatar */}
              <div className="flex flex-col items-center gap-3">
                <div className="relative">
                  <Avatar className="h-24 w-24 ring-2 ring-primary/20">
                    <AvatarImage src={avatarUrl} />
                    <AvatarFallback className="text-2xl bg-gradient-to-br from-primary/30 to-primary/10">
                      {groupInfo.type === 'group' ? <Users className="h-10 w-10 text-primary" /> : <Megaphone className="h-10 w-10 text-primary" />}
                    </AvatarFallback>
                  </Avatar>
                  {isOwner && (
                    <label className="absolute bottom-0 right-0 p-2 bg-primary text-primary-foreground rounded-full cursor-pointer hover:bg-primary/90 shadow-lg">
                      <Camera className="h-4 w-4" />
                      <input type="file" accept="image/*" className="hidden" onChange={handleAvatarUpload} />
                    </label>
                  )}
                </div>
              </div>

              {/* Editable fields */}
              {isOwner ? (
                <div className="space-y-4">
                  <div>
                    <Label className="text-xs text-muted-foreground mb-1.5 block">Nomi</Label>
                    <Input value={name} onChange={(e) => setName(e.target.value)}
                      placeholder={groupInfo.type === 'group' ? 'Guruh nomi' : 'Kanal nomi'}
                      className="rounded-xl bg-card/50 border-border/50" />
                  </div>
                  <div>
                    <Label className="text-xs text-muted-foreground mb-1.5 block">Tavsif</Label>
                    <Textarea value={description} onChange={(e) => setDescription(e.target.value)}
                      placeholder="Qisqacha tavsif..." rows={3}
                      className="rounded-xl bg-card/50 border-border/50 resize-none" />
                  </div>
                  <Button onClick={handleUpdate} disabled={isUpdating}
                    className="w-full rounded-xl bg-gradient-to-r from-[hsl(217,91%,60%)] to-[hsl(263,70%,50%)] text-white hover:opacity-90">
                    {isUpdating ? 'Saqlanmoqda...' : 'Saqlash'}
                  </Button>
                </div>
              ) : (
                <div className="space-y-1 text-center">
                  <h3 className="font-semibold text-lg">{groupInfo.name}</h3>
                  {groupInfo.description && <p className="text-sm text-muted-foreground">{groupInfo.description}</p>}
                </div>
              )}

              {/* Invite Link */}
              {(groupInfo.invite_link || isOwner) && (
                <div className="p-3 bg-card/50 border border-border/30 rounded-xl">
                  <div className="flex items-center gap-2 mb-2">
                    <Link className="h-4 w-4 text-muted-foreground" />
                    <span className="text-sm font-medium">Taklif havolasi</span>
                  </div>
                  {groupInfo.invite_link ? (
                    <div className="flex items-center gap-2 min-w-0">
                      <code className="text-xs bg-muted/50 p-2 rounded-lg truncate block whitespace-nowrap min-w-0" style={{ maxWidth: 'calc(100vw - 100px)' }}>{window.location.origin}/join/{groupInfo.invite_link}</code>
                      <Button variant="ghost" size="icon" onClick={copyInviteLink} className="h-8 w-8 rounded-lg shrink-0">
                        {linkCopied ? <Check className="h-4 w-4 text-green-500" /> : <Copy className="h-4 w-4" />}
                      </Button>
                      {isOwner && (
                        <Button variant="ghost" size="icon" onClick={revokeInviteLink} disabled={isGeneratingLink} className="h-8 w-8 rounded-lg shrink-0 text-destructive hover:bg-destructive/10 hover:text-destructive">
                          <RefreshCw className="h-4 w-4" />
                        </Button>
                      )}
                    </div>
                  ) : (
                    <Button
                      onClick={generateInviteLink}
                      disabled={isGeneratingLink}
                      className="w-full h-10 rounded-xl bg-primary/10 text-primary hover:bg-primary/15"
                      variant="ghost"
                    >
                      {isGeneratingLink ? 'Yaratilmoqda...' : 'Taklif havolasi yaratish'}
                    </Button>
                  )}
                </div>
              )}

              {/* Members */}
              <div>
                <div className="flex items-center justify-between mb-3">
                  <h3 className="font-semibold">A'zolar</h3>
                  {isOwner && (
                    <Button variant="outline" size="sm" onClick={() => setAddMemberOpen(true)}
                      className="rounded-xl gap-1.5 text-xs h-8 border-primary/30 text-primary hover:bg-primary/10">
                      <UserPlus className="h-3.5 w-3.5" />
                      Qo'shish
                    </Button>
                  )}
                </div>
                <div className="space-y-1">
                  {/* Owner */}
                  <div className="flex items-center gap-3 p-2.5 rounded-xl bg-primary/5 border border-primary/10">
                    <Avatar className="h-10 w-10">
                      <AvatarImage src={ownerProfile?.avatar_url || undefined} />
                      <AvatarFallback className="bg-gradient-to-br from-yellow-400/30 to-yellow-600/20">
                        <Crown className="h-4 w-4 text-yellow-500" />
                      </AvatarFallback>
                    </Avatar>
                    <div className="flex-1">
                      <p className="font-medium text-sm">{ownerProfile?.name || 'Egasi'}</p>
                      <p className="text-xs text-muted-foreground">
                        {user?.id === groupInfo.owner_id ? 'Siz · Egasi' : 'Egasi'}
                      </p>
                    </div>
                  </div>

                  {isLoadingMembers ? (
                    <p className="text-sm text-muted-foreground text-center py-4">Yuklanmoqda...</p>
                  ) : members.length === 0 ? (
                    <p className="text-sm text-muted-foreground text-center py-4">Boshqa a'zolar yo'q</p>
                  ) : (
                    members.map((member) => (
